#include <stack>

stack<int> s;

s.push(10); // add to the top
s.push(20);
s.push(30);

cout << s.top(); // 30 — look at the top without removing it

s.pop(); // remove the top element (30) — note: pop() returns nothing

#include <iostream>
#include <stack>

using namespace std;

int main()
{
    stack<int> s;
    s.push(10);
    s.push(20);
    s.push(30);

    while (!s.empty())
    {
        cout << s.top() << " ";
        s.pop();
    }

    return 0;
}

